Code possible avec jsonwebtoken : 

```js
const jwt = require('jsonwebtoken');

function authenticateToken(req, res, next) {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1]; // Bearer TOKEN

  if (!token) {
    return res.sendStatus(401); // Unauthorized : token manquant
  }

  jwt.verify(token, process.env.ACCESS_TOKEN_SECRET, (err, user) => {
    if (err) {
      return res.sendStatus(403); // Forbidden : token invalide
    }
    req.user = user;
    next();
  });
}
```

401 : absence de token ou format incorrect. 403 : token présent mais invalide (expiré, signature erronée).

```js
function authenticateToken(req, res, next) {
  let token = null;
  // Priorité au cookie
  if (req.cookies && req.cookies.auth_token) {
    token = req.cookies.auth_token;
  } else {
    const authHeader = req.headers['authorization'];
    token = authHeader && authHeader.split(' ')[1];
  }

  if (!token) return res.sendStatus(401);

  jwt.verify(token, process.env.ACCESS_TOKEN_SECRET, (err, user) => {
    if (err) return res.sendStatus(403);
    req.user = user;
    next();
  });
}
```
Il faut avoir configuré `cookie-parser` au préalable.

```js
const jwt = require('jsonwebtoken');

function generateAccessToken(user) {
  const payload = {
    userId: user.id,
    role: user.role
  };
  if (user.role === 'vendeur') {
    payload.storeId = user.storeId;
  }
  return jwt.sign(payload, process.env.JWT_SECRET, { expiresIn: '2h' });
}
```

```js
const jwt = require('jsonwebtoken');
const io = require('socket.io')(server);

io.use((socket, next) => {
  const token = socket.handshake.auth.token;
  if (!token) {
    return next(new Error('Authentication error: token missing'));
  }
  jwt.verify(token, process.env.JWT_SECRET, (err, user) => {
    if (err) return next(new Error('Authentication error: invalid token'));
    socket.user = user;
    next();
  });
});

io.on('connection', (socket) => {
  console.log(`User ${socket.user.userId} connected`);
  // ... rooms, messages, etc.
});
```
